export function SubmitButton({name, children}){
    console.log(name)
    return (
        <p type="submitButton">{name + children}</p>
    )
}

export function OptionButton({onQuizName, children}){
    return (
        <Button {...params} type="optionButton">{children}</Button>
    )
}

function Button({params, type,  children}){
    let style = "btn " + type;
    return (
        <button className={style} onClick={() => {params.onQuizName("Kek")}}>{children}</button>
    )
}
